    /// <summary>
    /// main
    /// </summary>
    public void main()
    {
        const str KKCDateArea = '0001';
        changecompany(KKCDateArea)
        {
            RecordInsertList salesLineRecordInsertList = new RecordInsertList(tableNum(KJP_SM_SalesLineFirstConfirmedHistory));

            SalesLine wkSalesLine;
            KJP_SM_SalesLineFirstConfirmedHistory wkSalesLineFirstConfirmedHistory;


            while select wkSalesLine
                where wkSalesLine.ShippingDateConfirmed != dateNull()
                notexists join wkSalesLineFirstConfirmedHistory
                where wkSalesLine.RecId == wkSalesLineFirstConfirmedHistory.RecIdSalesLine
            {
                wkSalesLineFirstConfirmedHistory.RecIdSalesLine             = wkSalesLine.RecId;
                wkSalesLineFirstConfirmedHistory.SalesId                    = wkSalesLine.SalesId;
                wkSalesLineFirstConfirmedHistory.LineNum                    = wkSalesLine.LineNum;
                wkSalesLineFirstConfirmedHistory.LineCreationSequenceNumber = wkSalesLine.LineCreationSequenceNumber;
                wkSalesLineFirstConfirmedHistory.ItemId                     = wkSalesLine.ItemId;
                wkSalesLineFirstConfirmedHistory.ShippingDateConfirmed      = wkSalesLine.ShippingDateConfirmed;
                wkSalesLineFirstConfirmedHistory.SalesQty                   = wkSalesLine.SalesQty;

                salesLineRecordInsertList.add(wkSalesLineFirstConfirmedHistory);
            }

            salesLineRecordInsertList.insertDatabase();
        }

    }
